--
-- Disparadores `products`
--
DELIMITER $$
CREATE TRIGGER `trg_products_bi` BEFORE INSERT ON `products` FOR EACH ROW BEGIN
  IF NEW.cylinder IS NOT NULL AND NEW.cylinder > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'cylinder debe ser <= 0';
  END IF;
  IF NEW.sphere IS NOT NULL AND (NEW.sphere < -40 OR NEW.sphere > 40) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sphere fuera de rango (-40 a 40)';
  END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_products_bu` BEFORE UPDATE ON `products` FOR EACH ROW BEGIN
  IF NEW.cylinder IS NOT NULL AND NEW.cylinder > 0 THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'cylinder debe ser <= 0';
  END IF;
  IF NEW.sphere IS NOT NULL AND (NEW.sphere < -40 OR NEW.sphere > 40) THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'sphere fuera de rango (-40 a 40)';
  END IF;
END
$$
DELIMITER ;

